import { useState } from 'react';
import { Link } from 'react-router-dom';


import Input from './components/reg-log-components/input';
import Checkbox from './components/reg-log-components/checkbox';
import Button from './components/reg-log-components/button';

const Login = ({ onLogin, changeOnRegisterPage }) => {

    const [username, setUsername] = useState('');
    
    const [password, setPassword] = useState('');
    const handleSubmit = (e) => {
      e.preventDefault(); // ЗУПИНЯЄ перезавантаження сторінки
      onLogin(); // Викликає функцію з App.js
    };


  return (
    <div className='reg-log'>
      <div className="auth-card">
        <div className="auth-form-container">
          <h2>Sign Up</h2>
          <form onSubmit={handleSubmit}>

            <Input 
              icon="/images/icons/username.svg" 
              alt="user"
              placeholder="Enter Username" 
              value={username} 
              onChange={(e) => setUsername(e.target.value)} 
            />

            <Input 
              icon="/images/icons/password.svg" 
              alt="lock"
              type="password" 
              placeholder="Enter Password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)} 
            />
            
            <button type="submit"></button>
          </form>
        </div>

        <div className="auth-image">
          <img src="/images/login.png" alt="Flat vector illustration of a woman standing next to a large smartphone showing a credit card and a green checkmark, symbolizing a completed transaction." />
        </div>


      </div>
    </div>
  );
};

export default Login;
